// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RepairTicket) predicate.RepairTicket {
	return predicate.RepairTicket(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RepairTicket) predicate.RepairTicket {
	return predicate.RepairTicket(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RepairTicket) predicate.RepairTicket {
	return predicate.RepairTicket(sql.NotPredicates(p))
}
